extern int omp_num_threads;

void lud_omp(float *a, int size)
{
    int i, j, k;
    float sum;

    omp_set_num_threads(omp_num_threads);

    #pragma omp parallel for default(none) private(i,j,k,sum) shared(a,size)
    for (i = 0; i < size; i++) {
        for (j = i; j < size; j++) {
            sum = a[i * size + j];
            for (k = 0; k < i; k++) {
                sum -= a[i * size + k] * a[k * size + j];
            }
            a[i * size + j] = sum;
        }

        for (j = i + 1; j < size; j++) {
            sum = a[j * size + i];
            for (k = 0; k < i; k++) {
                sum -= a[j * size + k] * a[k * size + i];
            }
            a[j * size + i] = sum / a[i * size + i];
        }
    }
}
